# --- Middleware / Instrumentation ---

@app.before_request
def before_request():
    g.start_time = time.time()
    endpoint = request.endpoint or "unknown"
    REQUEST_IN_PROGRESS.labels(method=request.method, endpoint=endpoint).inc()


@app.after_request
def after_request(response):
    if hasattr(g, "start_time"):
        latency = time.time() - g.start_time
        endpoint = request.endpoint or "unknown"
        method = request.method

        REQUEST_COUNT.labels(
            method=method,
            endpoint=endpoint,
            http_status=response.status_code,
        ).inc()

        REQUEST_LATENCY.labels(
            method=method,
            endpoint=endpoint,
        ).observe(latency)

        REQUEST_LATENCY_SUMMARY.labels(
            method=method,
            endpoint=endpoint,
        ).observe(latency)

        REQUEST_IN_PROGRESS.labels(method=method, endpoint=endpoint).dec()

    return response


@app.errorhandler(Exception)
def handle_exception(e):
    endpoint = request.endpoint or "unknown"
    ERROR_COUNT.labels(error_type=type(e).__name__, endpoint=endpoint).inc()
    return jsonify({"error": str(e)}), 500


# --- Helper decorators ---

def track_db_query(query_type, table):
    """Decorator to track database query duration."""
    def decorator(f):
        @wraps(f)
        def wrapper(*args, **kwargs):
            start = time.time()
            try:
                result = f(*args, **kwargs)
                return result
            finally:
                duration = time.time() - start
                DB_QUERY_DURATION.labels(
                    query_type=query_type, table=table
                ).observe(duration)
        return wrapper
    return decorator


def track_external_api(service_name):
    """Decorator to track external API call duration and status."""
    def decorator(f):
        @wraps(f)
        def wrapper(*args, **kwargs):
            start = time.time()
            try:
                result = f(*args, **kwargs)
                EXTERNAL_API_CALLS.labels(
                    service=service_name, status="success"
                ).inc()
                return result
            except Exception as e:
                EXTERNAL_API_CALLS.labels(
                    service=service_name, status="error"
                ).inc()
                raise
            finally:
                duration = time.time() - start
                EXTERNAL_API_LATENCY.labels(service=service_name).observe(duration)
        return wrapper
    return decorator


